public class HelloWorld {
    
    public static void main(String[] args) {
        System.out.printf("Hello, World!\n"); //first line
        System.out.printf("How old are you?\n"); 
        
        double d = 0.0; 
        while (d!=1.0) { 
          d += 0.1; 
        }
        System.out.println(d); 
    }
}

  